+fn safe_eigen_gap_reciprocal(lhs: f64, rhs: f64) -> f64 {
+    let gap = rhs - lhs;
+    let scale = lhs.abs().max(rhs.abs()).max(1.0);
+    let cluster_tol = 1e-8 * scale;
+    if gap.abs() <= cluster_tol {
+        0.0
+    } else {
+        1.0 / gap
+    }
+}
